changeSet.sql:
CREATE TABLE IF NOT EXISTS invoices ( id bigint not null, account_id BIGINT not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, invoice_number VARCHAR(50) UNIQUE NOT NULL, partner_id BIGINT , invoice_date DATE NOT NULL, due_date DATE NOT NULL, description TEXT, status VARCHAR(20) NOT NULL, total_amount DECIMAL(15,2) NOT NULL, journal_entry_id INTEGER REFERENCES journal_entries(id), CONSTRAINT invoices_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS invoices_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY invoices.id;
CREATE TABLE IF NOT EXISTS invoice_lines ( id bigint not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, invoice_id bigint REFERENCES invoices(id), description TEXT NOT NULL, quantity DECIMAL(15,2) NOT NULL, unit_price DECIMAL(15,2) NOT NULL, amount DECIMAL(15,2) NOT NULL, fin_account_id INTEGER REFERENCES fin_accounts(id), CONSTRAINT invoice_lines_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS invoice_lines_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY invoice_lines.id;
